package org.apache.commons.math.stat;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math.stat.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.stat.steps;

import org.apache.commons.math.stat.Frequency;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

public class StepDefs {

    private Frequency frequency;
    private Object nonComparableObject;
    private String stringValue;
    private Exception thrownException;

    @Given("a new Frequency instance created with the default constructor")
    public void a_new_Frequency_instance_created_with_the_default_constructor() {
        frequency = new Frequency();
    }

    @When("I call addValue with an object that does not implement Comparable")
    public void i_call_addValue_with_an_object_that_does_not_implement_Comparable() {
        // Create an object that doesn't implement Comparable
        nonComparableObject = new Object();
        try {
            frequency.addValue(nonComparableObject);
            thrownException = null;
        } catch (Exception e) {
            thrownException = e;
        }
    }

    @Then("the method should throw a ClassCastException")
    public void the_method_should_throw_a_ClassCastException() {
        assertNotNull("Expected ClassCastException to be thrown", thrownException);
        assertTrue("Expected ClassCastException but got " + thrownException.getClass().getSimpleName(), 
                   thrownException instanceof ClassCastException);
    }

    @Given("a Frequency instance created with the default constructor")
    public void a_Frequency_instance_created_with_the_default_constructor() {
        frequency = new Frequency();
    }

    @Given("the Frequency already contains a value of type Long")
    public void the_Frequency_already_contains_a_value_of_type_Long() {
        frequency.addValue(1L); // Add a Long value
    }

    @When("I call addValue with a value of type String")
    public void i_call_addValue_with_a_value_of_type_String() {
        stringValue = "test";
        try {
            frequency.addValue(stringValue);
            thrownException = null;
        } catch (Exception e) {
            thrownException = e;
        }
    }

    @Then("the method should throw an IllegalArgumentException")
    public void the_method_should_throw_an_IllegalArgumentException() {
        assertNotNull("Expected IllegalArgumentException to be thrown", thrownException);
        assertTrue("Expected IllegalArgumentException but got " + thrownException.getClass().getSimpleName(), 
                   thrownException instanceof IllegalArgumentException);
    }
}

